// File: utils/keys.ts
import { Config } from '../types';
import { Macro } from './macros';

type ConfigKey = keyof Config;
type NumericConfigKey = {
  [K in ConfigKey]: Config[K] extends number ? K : never
}[ConfigKey];

interface Parameter {
  name: NumericConfigKey | 'activeCellDensity';
  display: string;
  min: number;
  max: number;
  getValue: (config: Config) => number;
  setValue: (config: Config, value: number) => void;
}

interface KeyControls {
  setCurrentMacro: (macro: Macro) => void;
  clearCurrentMacro: () => void;
}

export function setupKeyControls(
  config: Config,
  onConfigChange: () => void,
  onHotkeyLog: (message: string) => void
): KeyControls {
  const parameters: Parameter[] = [
    {
      name: 'minCellSize',
      display: 'Grid Resolution (cellSize)',
      min: config.minCellSize,
      max: config.maxCellSize,
      getValue: (config) => config.minCellSize,
      setValue: (config, value) => { config.minCellSize = value; }
    },
    {
      name: 'minTickRate',
      display: 'Tick Rate',
      min: config.minTickRate,
      max: config.maxTickRate,
      getValue: (config) => config.minTickRate,
      setValue: (config, value) => { config.minTickRate = value; }
    },
    {
      name: 'activeCellDensity',
      display: 'Active Cell Density',
      min: 0.1,
      max: 1.0,
      getValue: (config) => config.activeCellDensity,
      setValue: (config, value) => { config.activeCellDensity = value; }
    }
  ];

  let activeParamIndex = 0;
  let currentMacro: Macro | null = null;

  onHotkeyLog(`Parameter: ${parameters[activeParamIndex].display}. Use Tab to cycle; ArrowUp/Down to adjust.`);

  window.addEventListener('keydown', (e: KeyboardEvent) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      activeParamIndex = (activeParamIndex + 1) % parameters.length;
      currentMacro = null;
      onHotkeyLog(`Active param: ${parameters[activeParamIndex].display}`);
      return;
    }

    if (currentMacro) {
      if (e.key === "ArrowUp") {
        currentMacro.setBaseline(currentMacro.getBaseline() + 0.1);
      } else if (e.key === "ArrowDown") {
        currentMacro.setBaseline(currentMacro.getBaseline() - 0.1);
      }
      return;
    }

    if (e.key === 'ArrowUp' || e.key === 'ArrowDown') {
      const param = parameters[activeParamIndex];
      const currentValue = param.getValue(config);
      const range = param.max - param.min;
      const step = range * 0.05;
      let newValue: number;
      if (e.key === 'ArrowUp') {
        newValue = currentValue + step;
        if (newValue > param.max) newValue = param.max;
      } else {
        newValue = currentValue - step;
        if (newValue < param.min) newValue = param.min;
      }
      newValue = (param.name === 'minTickRate' || param.name === 'minCellSize')
        ? Math.round(newValue)
        : Math.round(newValue * 100) / 100;
      onHotkeyLog(`${param.display} updated: ${currentValue} -> ${newValue}`);
      param.setValue(config, newValue);
      onConfigChange();
    }
  });

  return {
    setCurrentMacro: (macro: Macro) => {
      currentMacro = macro;
      onHotkeyLog(`Macro control activated.`);
    },
    clearCurrentMacro: () => {
      currentMacro = null;
      onHotkeyLog(`Macro control cleared.`);
    }
  };
} 