/**
 * tickManager.ts
 * 
 * Animation timing control system for the visual evolution engine.
 * 
 * This manager handles the core animation loop timing, providing a consistent
 * tick rate for the entire application. It uses the event bus to broadcast
 * tick events, allowing other components to synchronize with the animation
 * cycle. The tick rate is configurable and can be adjusted dynamically.
 * 
 * Key Features:
 * - Configurable tick rate
 * - Start/stop control
 * - Cycle counting
 * - Event-based synchronization
 * 
 * Interactions:
 * - Imports: EventBus from eventBus.ts, Config from config.ts
 * - Used by: Main application loop
 * - Provides: Animation timing events
 */

// File: utils/tickManager.ts
import { EventBus } from './eventBus.js';
import { config } from '../config.js';

export class TickManager {
  public eventBus: EventBus;
  private intervalId: NodeJS.Timer | null;
  private _cycleCount: number;

  constructor() {
    this.eventBus = new EventBus();
    this.intervalId = null;
    this._cycleCount = 0;
  }

  start(): void {
    // Always use the current tickRate from config
    const msPerTick = 1000 / config.tickRate;
    this.intervalId = setInterval(() => {
      this._cycleCount++;
      this.eventBus.emit('tick', { cycle: this._cycleCount });
    }, msPerTick);
  }

  stop(): void {
    if (this.intervalId) {
      clearInterval(this.intervalId);
      this.intervalId = null;
    }
  }

  getCycleCount(): number {
    return this._cycleCount;
  }
} 