/**
 * eventBus.ts
 * 
 * Event handling and communication system for the visual evolution engine.
 * 
 * This module implements a simple but effective event bus pattern, allowing
 * different parts of the application to communicate through events without
 * direct coupling. It supports event registration, emission, and handling
 * with type-safe event data.
 * 
 * Key Features:
 * - Event registration and deregistration
 * - Type-safe event emission
 * - Multiple listener support
 * 
 * Interactions:
 * - Used by: tickManager.ts for tick events
 * - Used by: Various UI components for state updates
 * - Provides: Application-wide event communication
 */

type EventListener = (data: any) => void;
type EventMap = Record<string, EventListener[]>;

export class EventBus {
  private events: EventMap;

  constructor() {
    this.events = {};
  }

  on(event: string, listener: EventListener): void {
    if (!this.events[event]) {
      this.events[event] = [];
    }
    this.events[event].push(listener);
  }

  emit(event: string, data: any): void {
    if (this.events[event]) {
      this.events[event].forEach(listener => listener(data));
    }
  }
} 