/**
 * macros.ts
 * 
 * Parameter modulation engine for the visual evolution system.
 * 
 * This module defines the core Macro class that handles parameter modulation
 * through Low Frequency Oscillators (LFOs). Each macro can modulate multiple
 * parameters using various trigonometric functions, with configurable periods,
 * baselines, and dampening factors.
 * 
 * Key Features:
 * - Multi-parameter modulation
 * - Configurable LFO waveforms
 * - Baseline value management
 * - Dampening control
 * 
 * Interactions:
 * - Used by: macrosUI.ts for UI control
 * - Affects: System parameters through modulation
 * - Provides: Time-based parameter automation
 */

export interface MacroTarget {
  path: string;
  influence: number;
  baseline?: number;
}

type TrigFunction = "sin" | "cos" | "tan" | "csc" | "sec" | "cot";

export class Macro {
  public targets: MacroTarget[] = [];
  public useCurrentBaseline: boolean = false;
  private currentBaseline: number = 0.5;
  public trigFunc: TrigFunction = "sin";
  public periodMultiplier: number = 1.0;
  public lfoPeriod: number = 100;
  public dampener: number = 0.5;
  public enabled: boolean = true;

  constructor() {
    // Constructor is now empty since we have default values above
  }

  public setBaseline(value: number): void {
    this.currentBaseline = value;
  }

  public getBaseline(): number {
    return this.currentBaseline;
  }

  public getModulation(tick: number): number {
    // Apply periodMultiplier: adjust the tick count
    const adjustedTick = tick * this.periodMultiplier;
    const phase = (adjustedTick % this.lfoPeriod) / this.lfoPeriod;
    let wave: number;
    switch (this.trigFunc) {
      case "sin":
        wave = Math.sin(phase * 2 * Math.PI);
        break;
      case "cos":
        wave = Math.cos(phase * 2 * Math.PI);
        break;
      case "tan":
        wave = Math.tan(phase * 2 * Math.PI);
        break;
      case "csc":
        wave = 1 / Math.sin(phase * 2 * Math.PI);
        break;
      case "sec":
        wave = 1 / Math.cos(phase * 2 * Math.PI);
        break;
      case "cot":
        wave = 1 / Math.tan(phase * 2 * Math.PI);
        break;
      default:
        wave = Math.sin(phase * 2 * Math.PI);
    }
    return wave * this.dampener;
  }
} 