/**
 * kaleidoscope.ts
 * 
 * Core visual pattern generation algorithm for the evolution engine.
 * 
 * This module implements a kaleidoscope-like pattern generation system that
 * creates symmetrical visual patterns. It works by maintaining a base quadrant
 * and reflecting it across both axes to create a full symmetrical pattern.
 * The algorithm integrates with the CreepingFig system for organic growth
 * patterns.
 * 
 * Key Features:
 * - Quadrant-based symmetrical pattern generation
 * - Dynamic pattern evolution
 * - Growth and decay management
 * - Boundary handling
 * 
 * Interactions:
 * - Imports: CreepingFig algorithm, Cell and BounceFunction types
 * - Used by: Main application for pattern generation
 * - Integrates with: Grid system for cell management
 */

import { CreepingFig } from './creepingFig.js';
import { Cell, BounceFunction } from '../types';

export class Kaleidoscope {
  private _cells: Cell[][];
  private _rows: number;
  private _cols: number;
  private bounceFn: BounceFunction;
  private baseRows: number;
  private baseCols: number;
  private baseCells: Cell[][];
  private creepingFig: CreepingFig;

  constructor(initialRow: number, initialCol: number, fullCells: Cell[][], rows: number, cols: number, bounceFn: BounceFunction) {
    this._cells = fullCells;
    this._rows = rows;
    this._cols = cols;
    this.bounceFn = bounceFn;

    // Base quadrant is top-left quarter
    this.baseRows = Math.floor(rows / 2);
    this.baseCols = Math.floor(cols / 2);

    // Create a sub-grid for the creeping fig
    this.baseCells = [];
    for (let i = 0; i < this.baseRows; i++) {
      this.baseCells[i] = [];
      for (let j = 0; j < this.baseCols; j++) {
        this.baseCells[i][j] = {
          state: 0,
          color: { r: 128, g: 0, b: 128, a: 1 },
          decaying: false,
          birth: 0,
          decayDelay: 0
        };
      }
    }

    // The single CreepingFig in that sub-grid
    const baseRow = Math.floor(this.baseRows / 2);
    const baseCol = Math.floor(this.baseCols / 2);
    this.creepingFig = new CreepingFig(
      baseRow,
      baseCol,
      this.baseCells,
      this.baseRows,
      this.baseCols,
      this.bounceBaseCoordinates.bind(this)
    );
  }

  // Public getters for required properties
  get cells(): Cell[][] {
    return this._cells;
  }

  get rows(): number {
    return this._rows;
  }

  get cols(): number {
    return this._cols;
  }

  // Required public methods
  public init(): void {
    // Reset base cells
    for (let i = 0; i < this.baseRows; i++) {
      for (let j = 0; j < this.baseCols; j++) {
        this.baseCells[i][j].state = 0;
      }
    }
    // Reflect to update the full grid
    this.reflectBaseQuadrant();
  }

  public reinitialize(): void {
    this.init();
    // Reset the creeping fig to its initial state
    const baseRow = Math.floor(this.baseRows / 2);
    const baseCol = Math.floor(this.baseCols / 2);
    this.creepingFig = new CreepingFig(
      baseRow,
      baseCol,
      this.baseCells,
      this.baseRows,
      this.baseCols,
      this.bounceBaseCoordinates.bind(this)
    );
  }

  public triggerChaos(): void {
    // Add some random activations in the base quadrant
    for (let i = 0; i < 5; i++) {
      const row = Math.floor(Math.random() * this.baseRows);
      const col = Math.floor(Math.random() * this.baseCols);
      this.baseCells[row][col].state = 1;
    }
    this.reflectBaseQuadrant();
  }

  update(growthMultiplier: number, decayMultiplier: number): void {
    // Update base creeper
    this.creepingFig.update(growthMultiplier);
    this.creepingFig.updateDecay(decayMultiplier);

    // Mirror the base quadrant to the full grid
    this.reflectBaseQuadrant();
  }

  private reflectBaseQuadrant(): void {
    for (let i = 0; i < this.baseRows; i++) {
      for (let j = 0; j < this.baseCols; j++) {
        const src = this.baseCells[i][j];
        this.copyCell(i, j, src);
        this.copyCell(i, j + this.baseCols, this.baseCells[i][this.baseCols - j - 1]);
        this.copyCell(
          i + this.baseRows,
          j,
          this.baseCells[this.baseRows - i - 1][j]
        );
        this.copyCell(
          i + this.baseRows,
          j + this.baseCols,
          this.baseCells[this.baseRows - i - 1][this.baseCols - j - 1]
        );
      }
    }
  }

  private copyCell(targetRow: number, targetCol: number, sourceCell: Cell): void {
    const row = Math.max(0, Math.min(targetRow, this._rows - 1));
    const col = Math.max(0, Math.min(targetCol, this._cols - 1));
    const mainCell = this._cells[row][col];

    mainCell.state = sourceCell.state;
    if (sourceCell.color) {
      mainCell.color = {
        r: sourceCell.color.r,
        g: sourceCell.color.g,
        b: sourceCell.color.b,
        a: sourceCell.color.a
      };
    }
    mainCell.decaying = sourceCell.decaying;
    mainCell.birth = sourceCell.birth;
    mainCell.decayDelay = sourceCell.decayDelay;
  }

  private bounceBaseCoordinates(i: number, j: number, direction: { di: number; dj: number }): { newI: number; newJ: number } {
    const newI = Math.max(0, Math.min(i, this.baseRows - 1));
    const newJ = Math.max(0, Math.min(j, this.baseCols - 1));
    return { newI, newJ };
  }
} 