/**
 * gridManager.ts
 * 
 * Core grid system for the visual evolution engine.
 * 
 * This manager handles the fundamental grid structure that underlies all visual
 * effects. It maintains a 2D array of cells and provides boundary management
 * through bounce mechanics. Each cell contains state information including
 * color, decay status, and birth time.
 * 
 * Key Features:
 * - 2D grid initialization and management
 * - Cell state tracking
 * - Boundary collision handling
 * 
 * Interactions:
 * - Imports: Cell, RGB types from types.ts
 * - Used by: Kaleidoscope and other visual algorithms
 * - Provides: Grid state access and boundary management
 */

import { Cell, RGB } from '../types';

interface Direction {
  di: number;
  dj: number;
}

interface BounceResult {
  newI: number;
  newJ: number;
  newDirection: Direction;
}

export class GridManager {
  public readonly rows: number;
  public readonly cols: number;
  public readonly cells: Cell[][];

  constructor(rows: number, cols: number) {
    this.rows = rows;
    this.cols = cols;
    this.cells = [];
    for (let i = 0; i < rows; i++) {
      this.cells[i] = [];
      for (let j = 0; j < cols; j++) {
        this.cells[i][j] = {
          state: 0,
          color: { r: 0, g: 0, b: 0, a: 1 },
          decaying: false,
          birth: 0,
          decayDelay: 0
        };
      }
    }
  }

  // Bounce: clamp i,j to grid boundaries. Return the new coords + direction if needed.
  bounceCoordinates(i: number, j: number, direction: Direction): BounceResult {
    const newI = Math.max(0, Math.min(i, this.rows - 1));
    const newJ = Math.max(0, Math.min(j, this.cols - 1));

    let newDirection = { di: direction.di, dj: direction.dj };
    if (i < 0 || i >= this.rows) newDirection.di = -direction.di;
    if (j < 0 || j >= this.cols) newDirection.dj = -direction.dj;

    return { newI, newJ, newDirection };
  }
} 